@namespace sv_bbfd2ee3af314d9ba4bf13affb1d1e7d.Components.Pages.Catalog

<div class="card h-100 product-card @(Product.InStock ? "" : "border-secondary")"
     @onclick="HandleCardClick"
     role="button">
    <div class="card-img-top bg-light d-flex align-items-center justify-content-center"
         style="height: 180px;"
         role="img"
         aria-label="@Product.Name">
        <span class="text-muted">@Product.Name</span>
    </div>
    <div class="card-body d-flex flex-column">
        <h6 class="card-title mb-1">@Product.Name</h6>
        <p class="card-text fw-bold text-primary mb-1">@Product.Price.ToString("C")</p>
        <p class="card-text mb-2" title="@($"{Product.Rating:F1} out of 5")">
            @RenderStars(Product.Rating)
        </p>
        @if (!Product.InStock)
        {
            <span class="badge bg-secondary mb-2">Out of Stock</span>
        }
        <button class="btn btn-sm btn-success mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="HandleAddToCart"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private async Task HandleCardClick()
    {
        await OnProductSelected.InvokeAsync(Product);
    }

    private async Task HandleAddToCart()
    {
        if (Product.InStock)
        {
            await OnAddToCart.InvokeAsync(Product);
        }
    }

    private static string RenderStars(double rating)
    {
        int fullStars = (int)Math.Round(rating);
        int emptyStars = 5 - fullStars;
        return new string('★', fullStars) + new string('☆', emptyStars);
    }
}

.product-card {
    cursor: pointer;
    transition: box-shadow 0.2s ease-in-out;
}

.product-card:hover {
    box-shadow: 0 0.25rem 0.75rem rgba(0, 0, 0, 0.15);
}

@namespace sv_bbfd2ee3af314d9ba4bf13affb1d1e7d.Components.Pages.Catalog

<div class="p-3 border rounded bg-light">
    <h5 class="mb-3">Filters</h5>

    <div class="mb-3">
        <label class="form-label fw-semibold">Category</label>
        @if (Categories is not null)
        {
            @foreach (var category in Categories)
            {
                <div class="form-check">
                    <input class="form-check-input" type="checkbox" id="@($"cat-{category}")"
                           checked="@IsSelected(category)"
                           @onchange="@(e => ToggleCategory(category, (bool)(e.Value ?? false)))" />
                    <label class="form-check-label" for="@($"cat-{category}")">@category</label>
                </div>
            }
        }
    </div>

    <div class="mb-3">
        <label class="form-label fw-semibold">Price Range</label>
        <div class="d-flex gap-2 align-items-center">
            <input type="number" class="form-control form-control-sm" placeholder="Min"
                   value="@MinPrice" @onchange="@(e => MinPrice = ParseDecimal(e.Value))" />
            <span>–</span>
            <input type="number" class="form-control form-control-sm" placeholder="Max"
                   value="@MaxPrice" @onchange="@(e => MaxPrice = ParseDecimal(e.Value))" />
        </div>
    </div>

    <div class="mb-3">
        <div class="form-check">
            <input class="form-check-input" type="checkbox" id="inStockOnly"
                   checked="@InStockOnly"
                   @onchange="@(e => InStockOnly = (bool)(e.Value ?? false))" />
            <label class="form-check-label" for="inStockOnly">In Stock Only</label>
        </div>
    </div>

    <div class="d-grid gap-2">
        <button class="btn btn-primary btn-sm" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFilters">Clear Filters</button>
    </div>
</div>

@code {
    [Parameter]
    public List<string>? Categories { get; set; }

    [Parameter]
    public ProductFilter? CurrentFilter { get; set; }

    [Parameter]
    public EventCallback<ProductFilter> OnFilterApplied { get; set; }

    private HashSet<string> SelectedCategories { get; set; } = new();
    private decimal? MinPrice { get; set; }
    private decimal? MaxPrice { get; set; }
    private bool InStockOnly { get; set; }

    protected override void OnParametersSet()
    {
        if (CurrentFilter is not null)
        {
            SelectedCategories = CurrentFilter.Categories is not null
                ? new HashSet<string>(CurrentFilter.Categories)
                : new HashSet<string>();
            MinPrice = CurrentFilter.MinPrice;
            MaxPrice = CurrentFilter.MaxPrice;
            InStockOnly = CurrentFilter.InStockOnly;
        }
    }

    private bool IsSelected(string category) => SelectedCategories.Contains(category);

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            SelectedCategories.Add(category);
        else
            SelectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: SelectedCategories.Count > 0 ? SelectedCategories.ToList() : null,
            MinPrice: MinPrice,
            MaxPrice: MaxPrice,
            InStockOnly: InStockOnly
        );
        await OnFilterApplied.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        SelectedCategories.Clear();
        MinPrice = null;
        MaxPrice = null;
        InStockOnly = false;
        await OnFilterApplied.InvokeAsync(new ProductFilter(null, null, null, false));
    }

    private static decimal? ParseDecimal(object? value)
    {
        if (value is null || string.IsNullOrWhiteSpace(value.ToString()))
            return null;
        return decimal.TryParse(value.ToString(), out var result) ? result : null;
    }
}

@namespace sv_bbfd2ee3af314d9ba4bf13affb1d1e7d.Components.Pages.Catalog

<div class="d-flex justify-content-between align-items-center mb-3 flex-wrap gap-2">
    <div class="d-flex align-items-center gap-2">
        <label for="sortBy" class="form-label mb-0 text-nowrap">Sort by:</label>
        <select id="sortBy" class="form-select form-select-sm" style="width: auto;"
                value="@SortBy" @onchange="HandleSortChanged">
            <option value="price_asc">Price: Low to High</option>
            <option value="price_desc">Price: High to Low</option>
            <option value="name_asc">Name: A–Z</option>
            <option value="rating_desc">Rating: Highest</option>
        </select>
    </div>
    <span class="text-muted">
        Showing @StartItem–@EndItem of @TotalCount products
    </span>
</div>

@code {
    [Parameter]
    public string SortBy { get; set; } = "price_asc";

    [Parameter]
    public int Page { get; set; }

    [Parameter]
    public int PageSize { get; set; }

    [Parameter]
    public int TotalCount { get; set; }

    [Parameter]
    public EventCallback<string> OnSortChanged { get; set; }

    private int StartItem => TotalCount == 0 ? 0 : (Page - 1) * PageSize + 1;
    private int EndItem => Math.Min(Page * PageSize, TotalCount);

    private async Task HandleSortChanged(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? "price_asc";
        await OnSortChanged.InvokeAsync(value);
    }
}

@namespace sv_bbfd2ee3af314d9ba4bf13affb1d1e7d.Components.Pages.Catalog

@if (TotalPages > 1)
{
    <nav aria-label="Product pagination">
        <ul class="pagination justify-content-center mt-4 mb-0">
            <li class="page-item @(Page <= 1 ? "disabled" : "")">
                <button class="page-link" @onclick="@(() => GoToPage(Page - 1))" disabled="@(Page <= 1)">
                    Previous
                </button>
            </li>
            @foreach (var p in PageNumbers)
            {
                <li class="page-item @(p == Page ? "active" : "")">
                    <button class="page-link" @onclick="@(() => GoToPage(p))">@p</button>
                </li>
            }
            <li class="page-item @(Page >= TotalPages ? "disabled" : "")">
                <button class="page-link" @onclick="@(() => GoToPage(Page + 1))" disabled="@(Page >= TotalPages)">
                    Next
                </button>
            </li>
        </ul>
    </nav>
}

@code {
    [Parameter]
    public int Page { get; set; }

    [Parameter]
    public int TotalCount { get; set; }

    [Parameter]
    public int PageSize { get; set; }

    [Parameter]
    public EventCallback<int> OnPageChanged { get; set; }

    private int TotalPages => PageSize > 0 ? (int)Math.Ceiling((double)TotalCount / PageSize) : 1;

    private IEnumerable<int> PageNumbers
    {
        get
        {
            // Show a window of up to 5 pages centered on the current page
            int start = Math.Max(1, Page - 2);
            int end = Math.Min(TotalPages, start + 4);
            start = Math.Max(1, end - 4);
            return Enumerable.Range(start, end - start + 1);
        }
    }

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages && page != Page)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }
}

@namespace sv_bbfd2ee3af314d9ba4bf13affb1d1e7d.Components.Pages.Catalog

<div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3">
    @foreach (var product in Products)
    {
        <div class="col">
            <ProductCard Product="@product"
                         OnProductSelected="OnProductSelected"
                         OnAddToCart="OnAddToCart" />
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public List<Product> Products { get; set; } = new();

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }
}

@page "/catalog"
@namespace sv_bbfd2ee3af314d9ba4bf13affb1d1e7d.Components.Pages.Catalog
@using sv_bbfd2ee3af314d9ba4bf13affb1d1e7d
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-4">Product Catalog</h3>

@if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
    </div>
}

<div class="row">
    <!-- Sidebar Filters -->
    <div class="col-md-3">
        <CatalogFilters Categories="@categories"
                        CurrentFilter="@filter"
                        OnFilterApplied="HandleFilterApplied" />
    </div>

    <!-- Main Content -->
    <div class="col-md-9">
        @if (isLoading)
        {
            <div class="d-flex justify-content-center align-items-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else if (result is not null && result.Items.Count > 0)
        {
            <CatalogToolbar SortBy="@sortBy"
                            Page="@currentPage"
                            PageSize="@PageSize"
                            TotalCount="@result.TotalCount"
                            OnSortChanged="HandleSortChanged" />

            <ProductGrid Products="@result.Items"
                         OnProductSelected="OnProductSelected"
                         OnAddToCart="HandleAddToCart" />

            <CatalogPagination Page="@currentPage"
                               TotalCount="@result.TotalCount"
                               PageSize="@PageSize"
                               OnPageChanged="HandlePageChanged" />
        }
        else
        {
            <div class="text-center py-5 text-muted">
                <h5>No products found</h5>
                <p>Try adjusting your filters to find what you're looking for.</p>
            </div>
        }
    </div>
</div>

@code {
    private const int PageSize = 12;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<string>? categories;
    private ProductFilter filter = new(null, null, null, false);
    private PagedResult<Product>? result;
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        try
        {
            isLoading = true;
            errorMessage = null;

            var categoriesTask = categories is null
                ? ProductService.GetCategoriesAsync()
                : Task.FromResult(categories);

            var searchTask = ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);

            await Task.WhenAll(categoriesTask, searchTask);

            categories = await categoriesTask;
            result = await searchTask;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load products. {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter newFilter)
    {
        filter = newFilter;
        currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandleSortChanged(string newSort)
    {
        sortBy = newSort;
        currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        currentPage = page;
        await LoadDataAsync();
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for add-to-cart functionality
        return Task.CompletedTask;
    }
}

