@namespace sv_bbfd2ee3af314d9ba4bf13affb1d1e7d.Components.Pages.Catalog

<div class="d-flex justify-content-between align-items-center mb-3 flex-wrap gap-2">
    <div class="d-flex align-items-center gap-2">
        <label for="sortBy" class="form-label mb-0 text-nowrap">Sort by:</label>
        <select id="sortBy" class="form-select form-select-sm" style="width: auto;"
                value="@SortBy" @onchange="HandleSortChanged">
            <option value="price_asc">Price: Low to High</option>
            <option value="price_desc">Price: High to Low</option>
            <option value="name_asc">Name: A–Z</option>
            <option value="rating_desc">Rating: Highest</option>
        </select>
    </div>
    <span class="text-muted">
        Showing @StartItem–@EndItem of @TotalCount products
    </span>
</div>

@code {
    [Parameter]
    public string SortBy { get; set; } = "price_asc";

    [Parameter]
    public int Page { get; set; }

    [Parameter]
    public int PageSize { get; set; }

    [Parameter]
    public int TotalCount { get; set; }

    [Parameter]
    public EventCallback<string> OnSortChanged { get; set; }

    private int StartItem => TotalCount == 0 ? 0 : (Page - 1) * PageSize + 1;
    private int EndItem => Math.Min(Page * PageSize, TotalCount);

    private async Task HandleSortChanged(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? "price_asc";
        await OnSortChanged.InvokeAsync(value);
    }
}

@namespace sv_bbfd2ee3af314d9ba4bf13affb1d1e7d.Components.Pages.Catalog

@if (TotalPages > 1)
{
    <nav aria-label="Product pagination">
        <ul class="pagination justify-content-center mt-4 mb-0">
            <li class="page-item @(Page <= 1 ? "disabled" : "")">
                <button class="page-link" @onclick="@(() => GoToPage(Page - 1))" disabled="@(Page <= 1)">
                    Previous
                </button>
            </li>
            @foreach (var p in PageNumbers)
            {
                <li class="page-item @(p == Page ? "active" : "")">
                    <button class="page-link" @onclick="@(() => GoToPage(p))">@p</button>
                </li>
            }
            <li class="page-item @(Page >= TotalPages ? "disabled" : "")">
                <button class="page-link" @onclick="@(() => GoToPage(Page + 1))" disabled="@(Page >= TotalPages)">
                    Next
                </button>
            </li>
        </ul>
    </nav>
}

@code {
    [Parameter]
    public int Page { get; set; }

    [Parameter]
    public int TotalCount { get; set; }

    [Parameter]
    public int PageSize { get; set; }

    [Parameter]
    public EventCallback<int> OnPageChanged { get; set; }

    private int TotalPages => PageSize > 0 ? (int)Math.Ceiling((double)TotalCount / PageSize) : 1;

    private IEnumerable<int> PageNumbers
    {
        get
        {
            int start = Math.Max(1, Page - 2);
            int end = Math.Min(TotalPages, start + 4);
            start = Math.Max(1, end - 4);
            return Enumerable.Range(start, end - start + 1);
        }
    }

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages && page != Page)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }
}

