@namespace sv_bbfd2ee3af314d9ba4bf13affb1d1e7d.Components.Pages.Catalog

<div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3">
    @foreach (var product in Products)
    {
        <div class="col">
            <ProductCard Product="@product"
                         OnProductSelected="OnProductSelected"
                         OnAddToCart="OnAddToCart" />
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public List<Product> Products { get; set; } = new();

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }
}

@page "/catalog"
@namespace sv_bbfd2ee3af314d9ba4bf13affb1d1e7d.Components.Pages.Catalog
@using sv_bbfd2ee3af314d9ba4bf13affb1d1e7d
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-4">Product Catalog</h3>

@if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
    </div>
}

<div class="row">
    <!-- Sidebar Filters -->
    <div class="col-md-3">
        <CatalogFilters Categories="@categories"
                        CurrentFilter="@filter"
                        OnFilterApplied="HandleFilterApplied" />
    </div>

    <!-- Main Content -->
    <div class="col-md-9">
        @if (isLoading)
        {
            <div class="d-flex justify-content-center align-items-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else if (result is not null && result.Items.Count > 0)
        {
            <CatalogToolbar SortBy="@sortBy"
                            Page="@currentPage"
                            PageSize="@PageSize"
                            TotalCount="@result.TotalCount"
                            OnSortChanged="HandleSortChanged" />

            <ProductGrid Products="@result.Items"
                         OnProductSelected="OnProductSelected"
                         OnAddToCart="HandleAddToCart" />

            <CatalogPagination Page="@currentPage"
                               TotalCount="@result.TotalCount"
                               PageSize="@PageSize"
                               OnPageChanged="HandlePageChanged" />
        }
        else
        {
            <div class="text-center py-5 text-muted">
                <h5>No products found</h5>
                <p>Try adjusting your filters to find what you're looking for.</p>
            </div>
        }
    </div>
</div>

@code {
    private const int PageSize = 12;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<string>? categories;
    private ProductFilter filter = new(null, null, null, false);
    private PagedResult<Product>? result;
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        try
        {
            isLoading = true;
            errorMessage = null;

            var categoriesTask = categories is null
                ? ProductService.GetCategoriesAsync()
                : Task.FromResult(categories);

            var searchTask = ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);

            await Task.WhenAll(categoriesTask, searchTask);

            categories = await categoriesTask;
            result = await searchTask;
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load products. {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter newFilter)
    {
        filter = newFilter;
        currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandleSortChanged(string newSort)
    {
        sortBy = newSort;
        currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        currentPage = page;
        await LoadDataAsync();
    }

    private Task HandleAddToCart(Product product)
    {
        return Task.CompletedTask;
    }
}

